{
  "plan": {
    "root_causes": [
      {
        "hypothesis": "Missing try/catch in dedicated store IPC handlers (PLUGIN-004/008) leaves Electron process vulnerable to unhandled rejections when store operations fail",
        "confidence": "high",
        "evidence": [
          "store-get at line 232 has try/catch → returns null; 6 dedicated handlers at lines 395-420 have none",
          "session-export-data, session-import-file also have try/catch — inconsistency is clear",
          "If store.get() throws (corrupted file, disk error), the unhandled rejection crashes the IPC pipeline"
        ]
      },
      {
        "hypothesis": "Local configs() signal is stale between mount/writes (PLUGIN-002/005/007). toggleEnabled and removePlugin read local signal, not fresh store state, causing lost writes on rapid toggles or post-install reads",
        "confidence": "high",
        "evidence": [
          "toggleEnabled: `const updated = configs().map(...)` reads local signal before setDesktopPluginConfig",
          "removePlugin: `const filtered = configs().filter(...)` reads local signal before setDesktopPluginConfig",
          "submitInstall: `configs().some(...)` and `[...configs(), newEntry]` both read local signal",
          "loadConfigs only runs on mount (line 128: `;(async () => await loadConfigs())()`)"
        ]
      },
      {
        "hypothesis": "Missing optional chaining on window.api calls (PLUGIN-001) causes TypeError if preload not exposed, which is caught and replaced with generic 'Failed to install' message, hiding the real problem",
        "confidence": "high",
        "evidence": [
          "dialog-install-plugin.tsx: submit() calls `window.api.getDesktopPluginConfig()` at line 68 without ?.",
          "openFilePicker at line 31 already has `?.()` — inconsistency within same file"
        ]
      },
      {
        "hypothesis": "Dynamic import of dialog-manage-plugins (PLUGIN-003) with no .catch() means import failure is a silent unhandled promise rejection",
        "confidence": "high",
        "evidence": [
          "index.tsx line 366: `void import('./dialog-manage-plugins').then(...)` — no .catch()",
          "Network or build errors would be swallowed"
        ]
      },
      {
        "hypothesis": "loadConfigs catch block (PLUGIN-006) is completely silent — no console.warn or console.error for debugging store failures",
        "confidence": "medium",
        "evidence": [
          "dialog-manage-plugins.tsx line 37: `} catch { ... }` — empty catch with no parameter, no logging"
        ]
      }
    ],
    "fixes": [
      {
        "id": "fix-A",
        "description": "Wrap all 6 dedicated store IPC handlers in try/catch with console.error. Get handlers return safe defaults; set handlers log and rethrow to preserve renderer error handling.",
        "files": ["packages/desktop/src/main/ipc.ts"],
        "before": "ipcMain.handle(\"get-desktop-custom-agents\", () => {\n    const store = getStore(\"desktop-custom-agents\")\n    return validateAndFilterAgents(store.get(\"agents\"))\n  })",
        "after": "ipcMain.handle(\"get-desktop-custom-agents\", () => {\n    try {\n      const store = getStore(\"desktop-custom-agents\")\n      return validateAndFilterAgents(store.get(\"agents\"))\n    } catch (e) {\n      console.error(\"get-desktop-custom-agents failed:\", e)\n      return []\n    }\n  })",
        "impact": {
          "affected_files": ["packages/desktop/src/main/ipc.ts"],
          "tests_to_run": ["desktop build check", "manual IPC test"]
        },
        "risks": [
          "Get handlers returning empty array on error means callers see empty data instead of an error — they might silently display 'no plugins' instead of showing an error state",
          "Callers that have try/catch around get calls (like dialog-install-plugin) will never enter their catch block for store failures, only for preload missing errors"
        ],
        "validation": [
          "Verify each handler has try { ... } catch (e) { console.error(...) } wrapping",
          "Verify get handlers return safe defaults: [] for agents/MCP, {configs: [], dropped: 0} for plugin",
          "Verify set handlers rethrow after logging to preserve renderer error recovery"
        ]
      },
      {
        "id": "fix-A-extended",
        "description": "Same try/catch pattern for set-desktop-custom-agents, set-desktop-mcp-servers, get-desktop-mcp-servers, get-desktop-plugin-config, set-desktop-plugin-config",
        "files": ["packages/desktop/src/main/ipc.ts"],
        "before": "See ipc.ts lines 395-420. Each handler is a 3-5 line function body with no error handling.",
        "after": "Each handler body wrapped in try/catch. Get: return safe default. Set: console.error + rethrow.",
        "impact": {
          "affected_files": ["packages/desktop/src/main/ipc.ts"],
          "tests_to_run": ["bun typecheck packages/desktop"]
        },
        "risks": [
          "set-desktop-plugin-config returns the validated result — returning safe default on error would break the caller that reads result.configs",
          "set-desktop-custom-agents and set-desktop-mcp-servers return void — callers have their own try/catch, but silently catching would prevent recovery"
        ],
        "validation": [
          "Verify all 6 handlers (3 get + 3 set) have try/catch",
          "Verify set-desktop-plugin-config rethrows (not silent), since caller reads result.configs in dialog-manage-plugins.tsx submitInstall etc."
        ]
      },
      {
        "id": "fix-B",
        "description": "Add optional chaining `?.()` to all window.api calls in dialog-*.tsx files that lack it, with early return/throw for undefined API",
        "files": [
          "packages/desktop/src/renderer/dialog-install-plugin.tsx",
          "packages/desktop/src/renderer/dialog-manage-plugins.tsx"
        ],
        "before": "const current = await window.api.getDesktopPluginConfig()",
        "after": "const current = await window.api.getDesktopPluginConfig?.()\nif (!current) { setError(\"Plugin config API not available\"); return }",
        "impact": {
          "affected_files": [
            "packages/desktop/src/renderer/dialog-install-plugin.tsx",
            "packages/desktop/src/renderer/dialog-manage-plugins.tsx"
          ],
          "tests_to_run": ["bun typecheck packages/desktop"]
        },
        "risks": [
          "window.api.xxx?.() always returns undefined for missing method, not throw. If existing callers rely on the function always existing (it should in production), this adds null-handling branches that may not be tested",
          "In loadConfigs, returning early when API is undefined makes the dialog skip loading silently — should fall back to empty state via the catch block instead"
        ],
        "validation": [
          "Every window.api.method() call (not already using ?.) in both dialog files gets ?.() suffix",
          "Every undefined result from ?.() is handled: either early return with setError, or throw to enter catch block"
        ]
      },
      {
        "id": "fix-C",
        "description": "toggleEnabled, removePlugin, and submitInstall fetch fresh state from window.api.getDesktopPluginConfig() instead of reading from local configs() signal. This eliminates lost writes from stale signal reads.",
        "files": ["packages/desktop/src/renderer/dialog-manage-plugins.tsx"],
        "before": "const toggleEnabled = async (name: string, current: boolean) => {\n    const updated = configs().map((c) => (c.name === name ? { ...c, enabled: !current } : c))\n    try {\n      const result = await window.api.setDesktopPluginConfig(updated)\n      setConfigs(result.configs)\n      setDropped(result.dropped)\n    } catch {\n      await loadConfigs()\n    }\n  }",
        "after": "const toggleEnabled = async (name: string, current: boolean) => {\n    try {\n      const fresh = await window.api.getDesktopPluginConfig()\n      const updated = fresh.configs.map((c) => (c.name === name ? { ...c, enabled: !current } : c))\n      const result = await window.api.setDesktopPluginConfig(updated)\n      setConfigs(result.configs)\n      setDropped(result.dropped)\n    } catch {\n      await loadConfigs()\n    }\n  }",
        "impact": {
          "affected_files": ["packages/desktop/src/renderer/dialog-manage-plugins.tsx"],
          "tests_to_run": ["Manual: rapid toggle multiple plugins, verify no lost writes"]
        },
        "risks": [
          "Extra API call per toggle/delete doubles the IPC roundtrip. For 3 rapid toggles, that's 6 IPC calls instead of 3. Load is still negligible (local electron-store is synchronous).",
          "If getDesktopPluginConfig succeeds but setDesktopPluginConfig fails, the 'catch' reloads from store — but the get was already fresh, so loadConfigs is a no-op recovery. This is fine.",
          "submitInstall currently checks `configs().some(c => c.name === name)` before setInstalling(true). Moving the fresh fetch inside try/catch changes error handling slightly."
        ],
        "validation": [
          "Ensure toggleEnabled reads from fresh.result.configs, not configs()",
          "Ensure removePlugin reads from fresh.result.configs, not configs()",
          "Ensure submitInstall reads from fresh.configs for duplicate check AND array building"
        ]
      },
      {
        "id": "fix-D",
        "description": "Add .catch() handler to dynamic import of dialog-manage-plugins in index.tsx menuTrigger",
        "files": ["packages/desktop/src/renderer/index.tsx"],
        "before": "void import(\"./dialog-manage-plugins\").then((x) => {\n  dialog.show(() => <x.DialogManagePlugins />)\n})",
        "after": "void import(\"./dialog-manage-plugins\").then((x) => {\n  dialog.show(() => <x.DialogManagePlugins />)\n}).catch((e) => {\n  console.error(\"Failed to load plugin manager dialog:\", e)\n})",
        "impact": {
          "affected_files": ["packages/desktop/src/renderer/index.tsx"],
          "tests_to_run": ["bun typecheck packages/desktop"]
        },
        "risks": [
          "Minimal — .catch() on dynamic import is standard practice",
          "If import fails, the dialog simply won't open. No user-facing error — could be confusing. But this is a build/runtime error that shouldn't happen in production."
        ],
        "validation": [
          "Verify .catch() handler exists with console.error",
          "Verify bun typecheck passes"
        ]
      },
      {
        "id": "fix-E",
        "description": "Add console.warn to the silent catch block in loadConfigs",
        "files": ["packages/desktop/src/renderer/dialog-manage-plugins.tsx"],
        "before": "    } catch {\n      setConfigs([])\n      setDropped(0)\n    }",
        "after": "    } catch (e) {\n      console.warn(\"Failed to load plugin configs:\", e)\n      setConfigs([])\n      setDropped(0)\n    }",
        "impact": {
          "affected_files": ["packages/desktop/src/renderer/dialog-manage-plugins.tsx"],
          "tests_to_run": ["bun typecheck packages/desktop"]
        },
        "risks": [
          "None. Adds diagnostic logging only. The catch parameter 'e' is never used for control flow."
        ],
        "validation": [
          "Verify catch block has console.warn with the error parameter"
        ]
      }
    ],
    "apply_order": ["fix-A", "fix-A-extended", "fix-B", "fix-C", "fix-D", "fix-E"],
    "rollback_plan": "Revert each fix in reverse order (fix-E first, then fix-D, fix-C, fix-B, fix-A-extended, fix-A). Each fix touches independent code regions — no cascading dependencies."
  }
}
